// Code Node Configuration: "Run Once for All Items", Language: "JavaScript"
// Get the article outline from the input
const input = $input.first().json;

// ============================================
// HELPER FUNCTIONS
// ============================================

/**
 * Extract outline from various input formats
 */
function getOutline(input) {
  if (Array.isArray(input)) {
    return input[0]?.output || input[0] || {};
  }
  return input?.output || input || {};
}

/**
 * Case-insensitive property getter
 */
function getProperty(obj, propertyName) {
  if (!obj || typeof obj !== 'object') return undefined;

  // Direct match
  if (obj.hasOwnProperty(propertyName)) return obj[propertyName];

  // Case-insensitive match
  const lowerPropName = propertyName.toLowerCase();
  for (const key in obj) {
    if (key.toLowerCase() === lowerPropName) return obj[key];
  }

  return undefined;
}

/**
 * Safely get array property with fallback
 */
function getArrayProperty(obj, propertyName, defaultValue = []) {
  const value = getProperty(obj, propertyName);
  return Array.isArray(value) ? value : defaultValue;
}

// ============================================
// MAIN LOGIC
// ============================================

const outline = getOutline(input);

// Extract top-level fields
const selectedKeywords = getArrayProperty(outline, 'selected_keywords');
const mainKeyword = getProperty(outline, 'main_keyword_for_url') || '';
const title = getProperty(outline, 'title') || 'Untitled';
const metaTitle = getProperty(outline, 'meta_title') || title;
const metaDescription = getProperty(outline, 'meta_description') || '';
const url = getProperty(outline, 'url') || '';
const summary = getProperty(outline, 'summary') || '';
const introduction = getProperty(outline, 'introduction') || '';
const conclusion = getProperty(outline, 'conclusion') || '';
const cta = getProperty(outline, 'cta') || '';

// ============================================
// PROCESS BODY SECTIONS
// ============================================

const bodySectionsArray = getArrayProperty(outline, 'body_sections').map((section, index) => {
  const h2 = getProperty(section, 'h2') || `Section ${index + 1}`;
  const description = getProperty(section, 'description') || '';
  const keywords = getArrayProperty(section, 'keywords');

  // Process subsections (H3s)
  const subsections = getArrayProperty(section, 'subsections').map(sub => ({
    h3: getProperty(sub, 'h3') || '',
    description: getProperty(sub, 'description') || ''
  }));

  return {
    h2: h2,
    description: description,
    keywords: keywords,
    subsections: subsections
  };
});

// ============================================
// CREATE LLM-READABLE TEXT VERSION
// ============================================

let bodySectionsText = '';

bodySectionsArray.forEach((section, index) => {
  // Section header
  bodySectionsText += `═══════════════════════════════════════════════\n`;
  bodySectionsText += `SECTION ${index + 1}: ${section.h2}\n`;
  bodySectionsText += `═══════════════════════════════════════════════\n\n`;

  // Section description
  bodySectionsText += `📝 INSTRUCTIONS:\n${section.description}\n\n`;

  // Keywords for this section
  if (section.keywords.length > 0) {
    bodySectionsText += `🔑 KEYWORDS TO INCLUDE:\n${section.keywords.join(', ')}\n\n`;
  }

  // Subsections (H3s)
  if (section.subsections.length > 0) {
    bodySectionsText += `📋 SUBSECTIONS:\n`;
    section.subsections.forEach((sub, subIndex) => {
      bodySectionsText += `\n  ${subIndex + 1}. ${sub.h3}\n`;
      bodySectionsText += `     Description: ${sub.description}\n`;
    });
    bodySectionsText += `\n`;
  }

  // Separator between sections
  bodySectionsText += `\n`;
});

// ============================================
// ASSEMBLE FINAL OUTPUT
// ============================================

const finalOutput = {
  // Keyword strategy
  "selected_keywords": selectedKeywords,
  "main_keyword_for_url": mainKeyword,

  // SEO metadata
  "title": title,
  "meta_title": metaTitle,
  "meta_description": metaDescription,
  "url": url,

  // Content structure
  "summary": summary,
  "introduction_description": introduction,

  // Body sections (structured)
  "body_sections": bodySectionsArray,

  // Body sections (LLM-readable text format)
  "body_sections_text": bodySectionsText.trim(),

  // Closing sections
  "conclusion_description": conclusion,
  "cta": cta,

  // Metadata for tracking
  "total_sections": bodySectionsArray.length,
  "total_keywords": selectedKeywords.length,
  "word_count_target": "1000-1200 words"
};

// ============================================
// RETURN OUTPUT
// ============================================

return [{
  json: finalOutput
}];

// --- Get the Inputs ---
// This code assumes it receives the direct output from the LLM node.
// We are now also adding the original outline from the very first node.
// To do this, you might need to use a "Merge" node before this Code node to combine the two data sources.
const llmOutput = $input.first().json.output || {};
const originalInput = $input.all().slice(0, -1).pop()?.json || {}; // Gets data from the node before the LLM
let articleText = llmOutput.article || '';
const originalOutlineText = originalInput.body_sections_text;

// --- 1. Create a List of "True" H2 Headings (Safely) ---
const trueH2Headings = [];
if (originalOutlineText && typeof originalOutlineText === 'string') {
  const outlineLines = originalOutlineText.split('\n');
  for (const line of outlineLines) {
    if (line.startsWith('SECTION')) {
      const heading = line.substring(line.indexOf(':') + 1).trim();
      trueH2Headings.push(heading);
    }
  }
} else {
  console.log("Warning: 'body_sections_text' from original input not found. Skipping heading correction.");
}

// --- 2. Perform Initial Fixes on the Raw Text ---
// Using chained .replace() methods for efficiency.

// Fix #1: Correct Year Typo
let correctedText = articleText.replace(/2024/g, '2025');

// Fix #2: Correct Heading Levels (Smarter Logic)
const lines = correctedText.split('\n');
const correctedLines = lines.map(line => {
  if (trueH2Headings.length > 0 && line.startsWith('## ')) {
    const currentHeading = line.substring(3).trim();
    // Check if the current heading is a real H2 from our map
    const isTrueH2 = trueH2Headings.some(h2 => h2.includes(currentHeading) || currentHeading.includes(h2));
    if (!isTrueH2) {
      // If it's not a true H2, demote it to an H3
      return '### ' + currentHeading;
    }
  }
  return line;
});
correctedText = correctedLines.join('\n');


// --- 3. Apply "One Sentence Per Line" Formatting (Refined Method) ---
// This new method is more reliable.
// It finds punctuation followed by a space and replaces it with the punctuation and a newline.
// It handles multiple spaces and existing newlines gracefully.
// The lookbehind `(?<=[.!?])` ensures we match the space *after* punctuation.
const formattedArticle = correctedText.replace(/(?<=[.!?])\s+/g, '\n');


// --- 4. Finalize and Return ---
// Rebuild the output object to ensure a clean final structure
const finalOutput = {
  title: llmOutput.title || '',
  meta_title: llmOutput.meta_title || '',
  meta_description: llmOutput.meta_description || '',
  url: llmOutput.url || '',
  article: formattedArticle
};

return [{ json: { output: finalOutput } }];

function insertImageAfterBody(cont, imgUrl) {
  // Check if content and image URL are provided

  // Find the position of the <body> tag (case-insensitive)
  const bodyTagRegex = /<\/h1>/i;
  const match = cont.match(bodyTagRegex);


  // Get the position right after the <body> tag
  const bodyTagEnd = match.index + match[0].length;

  // Create the img tag
  const imgTag = `\n <img src="${imgUrl}" alt="Featured Image" style="max-width: 100%; height: auto;">\n`;

  // Insert the image tag after the body tag
  const updatedContent = 
    cont.slice(0, bodyTagEnd) + 
    imgTag + 
    cont.slice(bodyTagEnd);

  return updatedContent;
}

// Usage example:
const cont =$('structuring').first().json.output;

const imgUrl =$input.first().json.images[0].url;

const result = insertImageAfterBody(cont, imgUrl);
return {result};

let content = $('Code in JavaScript2').first().json.result;

// STEP 1: Remove HTML wrapper (DOCTYPE, html, head, body tags)
if (content.includes('<!DOCTYPE')) {
  // Extract only content between <article> and </article>
  const articleMatch = content.match(/<article[^>]*>([\s\S]*?)<\/article>/i);
  if (articleMatch) {
    content = articleMatch[1]; // Get content inside <article> tags
  }
}

// STEP 2: Remove the FIRST <h1> tag AND its content completely
content = content.replace(/<div[^>]*>\s*<h1[^>]*>.*?<\/h1>\s*<\/div>/is, ''); // If h1 is wrapped in div
content = content.replace(/<h1[^>]*>.*?<\/h1>/is, ''); // Remove bare h1 with content

// STEP 3: Optional - remove stray <br> around headings and images
content = content.replace(/<br\s*\/?>\s*(?=<h[1-6]\b)/gi, '');
content = content.replace(/(?<=<\/h[1-6]>)\s*<br\s*\/?>/gi, '');
content = content.replace(/<br\s*\/?>\s*(?=<img\b)/gi, '');
content = content.replace(/(?<=<img\b[^>]*>)\s*<br\s*\/?>/gi, '');

// STEP 4: Add spacing around ALL headings (h2–h6, NOT h1 since we removed it)
content = content.replace(
  /(<h[2-6]\b[^>]*>[\s\S]*?<\/h[2-6]>)/gi,
  '<div style="margin-top:24px; margin-bottom:16px;">$1</div>'
);

// STEP 5: Add spacing around ALL images
content = content.replace(
  /(<img\b[^>]*>)/gi,
  '<div style="margin-top:16px; margin-bottom:16px;">$1</div>'
);

// STEP 6: Clean up any leading/trailing whitespace
content = content.trim();

return [
  {
    json: {
      content,
    },
  },
];

// n8n Code Node - Merge + Dedupe + Rank keywords from multi-task DataForSEO response
// Input: DataForSEO response with tasks[] (10 seeds)
// Output: top keywords overall + top keywords per seed

try {
  // -----------------------------
  // CONFIG (tune these)
  // -----------------------------
  const CONFIG = {
    totalOverall: 100,         // final top keywords overall
    perSeedTop: 25,            // top keywords per seed keyword
    minEffectiveSV: 10,        // lower = more output
    minAdsSV: 20,              // lower = more output
    minScore: 15,              // lower = more output
    mix: { short: 10, medium: 30, long: 60 }, // split for overall selection
    preferClickstream: true,   // use clickstream volume if present
  };

  // -----------------------------
  // READ INPUT (supports 1+ items)
  // -----------------------------
  const inputs = $input.all().map(i => i.json);
  if (!inputs.length) throw new Error("No input data received");

  // If your HTTP node returns only one item, it's usually here:
  // inputs[0].tasks
  // But we support multiple incoming items too.
  const allTasks = [];
  for (const j of inputs) {
    if (Array.isArray(j?.tasks)) allTasks.push(...j.tasks);
    else if (Array.isArray(j?.data?.tasks)) allTasks.push(...j.data.tasks); // fallback (rare)
  }

  if (!allTasks.length) {
    // Sometimes user passes already-at-result-level objects (less common)
    // Try to treat each input as a "task-like" object:
    for (const j of inputs) {
      if (j?.result?.[0]?.items) allTasks.push({ result: j.result, data: { keyword: j.seed_keyword || j.keyword } });
    }
  }

  if (!allTasks.length) throw new Error("Could not find tasks[] in the input. Make sure the HTTP node returns the full DataForSEO response.");

  // -----------------------------
  // HELPERS
  // -----------------------------
  const norm = (s) => String(s || "").trim().toLowerCase().replace(/\s+/g, " ");

  function getKeywordType(wordsCount) {
    if (wordsCount <= 2) return "short-tail";
    if (wordsCount <= 4) return "medium-tail";
    return "long-tail";
  }

  function safeNum(v, fallback = 0) {
    const n = Number(v);
    return Number.isFinite(n) ? n : fallback;
  }

  function scoreKeyword({ effectiveSV, adsSV, cpc, competition, competitionLevel, kd, intent }) {
    // More permissive scoring so you get more outputs.
    // 1) Volume (max 40)
    const volBase = CONFIG.preferClickstream ? effectiveSV : adsSV;
    const volumeScore = Math.min(40, (Math.log10(volBase + 1) / Math.log10(8000)) * 40);

    // 2) Competition (max 20) - lower better
    let compScore = 12;
    if (competitionLevel === "LOW") compScore = 20;
    else if (competitionLevel === "MEDIUM") compScore = 14;
    else if (competitionLevel === "HIGH") compScore = 7;
    else compScore = Math.max(0, 20 - safeNum(competition) * 20);

    // 3) Difficulty (max 20) - lower better (assume moderate if missing)
    const kdSafe = kd > 0 ? kd : 35;
    const diffScore = Math.max(0, 20 - (kdSafe / 7));

    // 4) Intent (max 15) - blogs prefer informational/commercial
    let intentScore = 8;
    if (intent === "informational") intentScore = 15;
    else if (intent === "commercial") intentScore = 12;
    else if (intent === "transactional") intentScore = 10;
    else if (intent === "navigational") intentScore = 6;

    // 5) CPC (max 5) - commercial value signal
    const cpcScore = Math.min(5, (safeNum(cpc) / 2) * 5);

    return Math.round(volumeScore + compScore + diffScore + intentScore + cpcScore);
  }

  // -----------------------------
  // EXTRACT + MERGE + DEDUPE
  // -----------------------------
  const dedupeMap = new Map(); // keywordLower -> best object
  const keywordsBySeed = {};   // seed -> array

  let totalAnalyzed = 0;
  const seeds = [];

  for (const task of allTasks) {
    const seed = task?.data?.keyword || task?.result?.[0]?.seed_keyword || "unknown";
    seeds.push(seed);

    const items = task?.result?.[0]?.items || [];
    if (!keywordsBySeed[seed]) keywordsBySeed[seed] = [];

    for (const it of items) {
      totalAnalyzed++;

      const keyword = it?.keyword;
      if (!keyword) continue;

      const keywordLower = norm(keyword);
      if (!keywordLower) continue;

      const clickstreamSV = safeNum(it?.clickstream_keyword_info?.search_volume, 0);
      const adsSV = safeNum(it?.keyword_info?.search_volume, 0);
      const effectiveSV = (CONFIG.preferClickstream && clickstreamSV > 0) ? clickstreamSV : adsSV;

      const wordsCount = safeNum(it?.keyword_properties?.words_count, keyword.split(/\s+/).length);
      const keywordType = getKeywordType(wordsCount);

      // Light filter (so you still get plenty)
      if (effectiveSV < CONFIG.minEffectiveSV && adsSV < CONFIG.minAdsSV) continue;

      const cpc = safeNum(it?.keyword_info?.cpc, 0);
      const competition = safeNum(it?.keyword_info?.competition, 0);
      const competitionLevel = it?.keyword_info?.competition_level || "UNKNOWN";
      const kd = safeNum(it?.keyword_properties?.keyword_difficulty, 0);
      const intent = it?.search_intent_info?.main_intent || "unknown";

      const serpTypes = it?.serp_info?.serp_item_types || [];
      const checkUrl = it?.serp_info?.check_url || null;

      const s = scoreKeyword({ effectiveSV, adsSV, cpc, competition, competitionLevel, kd, intent });
      if (s < CONFIG.minScore) continue;

      const obj = {
        keyword,
        keywordLower,
        seed_sources: [seed],
        keywordType,
        score: s,
        metrics: {
          effectiveSV,
          clickstreamSV,
          adsSV,
          cpc: Math.round(cpc * 100) / 100,
          competition: Math.round(competition * 100) / 100,
          competitionLevel,
          keywordDifficulty: kd || null,
          wordsCount,
          intent,
        },
        serp: {
          serp_item_types: serpTypes,
          check_url: checkUrl,
        },
      };

      // Store per-seed (we'll trim later)
      keywordsBySeed[seed].push(obj);

      // Dedupe across all seeds: keep the best-scoring version, merge seed_sources
      const existing = dedupeMap.get(keywordLower);
      if (!existing) {
        dedupeMap.set(keywordLower, obj);
      } else {
        // merge sources
        const mergedSources = new Set([...(existing.seed_sources || []), seed]);
        const best = (obj.score > existing.score) ? obj : existing;
        best.seed_sources = Array.from(mergedSources);
        dedupeMap.set(keywordLower, best);
      }
    }
  }

  // Unique merged list
  const merged = Array.from(dedupeMap.values());
  merged.sort((a, b) => b.score - a.score);

  // -----------------------------
  // BALANCED MIX (overall)
  // -----------------------------
  const short = merged.filter(k => k.keywordType === "short-tail");
  const medium = merged.filter(k => k.keywordType === "medium-tail");
  const long = merged.filter(k => k.keywordType === "long-tail");

  const overallSelected = [
    ...short.slice(0, CONFIG.mix.short),
    ...medium.slice(0, CONFIG.mix.medium),
    ...long.slice(0, CONFIG.mix.long),
  ];

  // Fill if not enough
  if (overallSelected.length < CONFIG.totalOverall) {
    const selectedSet = new Set(overallSelected.map(k => k.keywordLower));
    const remaining = merged.filter(k => !selectedSet.has(k.keywordLower));
    overallSelected.push(...remaining.slice(0, CONFIG.totalOverall - overallSelected.length));
  }

  const keywords_overall = overallSelected
    .slice(0, CONFIG.totalOverall)
    .sort((a, b) => b.score - a.score);

  // -----------------------------
  // TOP PER SEED
  // -----------------------------
  const keywords_by_seed = {};
  for (const seed of Object.keys(keywordsBySeed)) {
    keywords_by_seed[seed] = keywordsBySeed[seed]
      .sort((a, b) => b.score - a.score)
      .slice(0, CONFIG.perSeedTop);
  }

  // -----------------------------
  // OUTPUT
  // -----------------------------
  const output = {
    success: true,
    category:$('Code in JavaScript1').first().json.category,
    day:$('Get row(s) in sheet').first().json.day,
    seeds: Array.from(new Set(seeds)),
    totalTasks: Array.from(new Set(seeds)).length,
    totalAnalyzed,
    totalMergedUnique: merged.length,
    totalSelectedOverall: keywords_overall.length,
    configUsed: CONFIG,
    keywords_overall,
    keywords_by_seed,
    summary: {
      overall_short: keywords_overall.filter(k => k.keywordType === "short-tail").length,
      overall_medium: keywords_overall.filter(k => k.keywordType === "medium-tail").length,
      overall_long: keywords_overall.filter(k => k.keywordType === "long-tail").length,
      topKeyword: keywords_overall[0]?.keyword || null,
      topScore: keywords_overall[0]?.score || null,
    },
  };

  return [{ json: output }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: error.message,
      stack: error.stack,
    }
  }];
}
